// Normalize and validate incoming claim payload
const body = $input.first().json;

const required = ['claim_id', 'customer_id', 'policy_id', 'claim_type', 'claim_amount', 'description'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Normalize claim_type
const claimTypeMap = {
  'fire': 'fire', 'brand': 'fire',
  'water': 'water', 'wasser': 'water',
  'theft': 'theft', 'diebstahl': 'theft',
  'accident': 'accident', 'unfall': 'accident',
  'fraud': 'fraud_suspected'
};

const normalizedType = claimTypeMap[body.claim_type?.toLowerCase()] || body.claim_type;

return [{
  json: {
    ...body,
    claim_type: normalizedType,
    claim_amount: parseFloat(body.claim_amount),
    currency: body.currency || 'CHF',
    submission_channel: body.submission_channel || 'web',
    attachments: body.attachments || [],
    received_at: new Date().toISOString(),
    pipeline: 'claims'
  }
}];

// Merge claim data with customer + policy context
const claim = $('Validate & Normalize').first().json;
const customer = $('Load Customer Data').first().json || {};
const policy = $('Load Policy & Claims History').first().json || {};

const enriched = {
  // Core claim fields
  claim_id: claim.claim_id,
  customer_id: claim.customer_id,
  policy_id: claim.policy_id,
  claim_type: claim.claim_type,
  claim_amount: claim.claim_amount,
  currency: claim.currency,
  description: claim.description,
  submission_channel: claim.submission_channel,
  attachments: claim.attachments,

  // Customer enrichment
  customer_since_years: customer.years_as_customer || null,
  previous_claims_count: customer.total_claims_count || 0,
  previous_claims_total: customer.total_claims_amount || 0,
  customer_ltv: customer.ltv_estimate || null,

  // Policy enrichment
  policy_type: policy.product_name || null,
  policy_annual_premium: policy.annual_premium || null,
  policy_coverage_limit: policy.coverage_limit || null,
};

return [{ json: enriched }];

// Apply Orchestrator business rules on top of agent result
const agent = $json;

// Hard business rule overrides
let finalRoute = agent.recommended_route;
let escalationReason = null;

// Rule 1: Auto-limit override — amounts above CHF 50k cannot be auto-processed
if (agent.recommended_route === 'auto_process' && $('Merge Context').first().json.claim_amount > 50000) {
  finalRoute = 'manual_review';
  escalationReason = 'Amount exceeds auto-processing limit (CHF 50k)';
}

// Rule 2: Fraud score hard cutoff — always SIU above 0.75
if (agent.fraud_score >= 0.75) {
  finalRoute = 'siu_referral';
  escalationReason = `Fraud score ${agent.fraud_score.toFixed(2)} exceeds SIU threshold (0.75)`;
}

// Rule 3: Low confidence fallback
if (agent.confidence < 0.60 && finalRoute === 'auto_process') {
  finalRoute = 'manual_review';
  escalationReason = `Agent confidence too low for automation (${agent.confidence.toFixed(2)})`;
}

return [{
  json: {
    ...agent,
    final_route: finalRoute,
    orchestrator_override: finalRoute !== agent.recommended_route,
    escalation_reason: escalationReason,
    orchestrated_at: new Date().toISOString()
  }
}];

// AUTO PROCESS: Standard claim, trigger automated payout workflow
const data = $json;
return [{
  json: {
    action: 'auto_process',
    claim_id: data.claim_id,
    estimated_payout: data.estimated_payout,
    priority: data.priority,
    message: `Claim ${data.claim_id} queued for automated processing`,
    next_system: 'claims_management_auto',
    processed_at: new Date().toISOString()
  }
}];

// MANUAL REVIEW: Route to Human-in-the-Loop queue
const data = $json;
return [{
  json: {
    action: 'manual_review',
    claim_id: data.claim_id,
    priority: data.priority,
    flags: data.flags,
    reasoning: data.reasoning,
    override_reason: data.escalation_reason,
    assigned_queue: data.priority === 'critical' ? 'senior_adjuster' : 'standard_review',
    message: `Claim ${data.claim_id} sent to manual review queue`,
    processed_at: new Date().toISOString()
  }
}];

// SIU REFERRAL: Special Investigations Unit escalation
const data = $json;
return [{
  json: {
    action: 'siu_referral',
    claim_id: data.claim_id,
    fraud_score: data.fraud_score,
    flags: data.flags,
    reasoning: data.reasoning,
    alert_level: 'HIGH',
    message: `FRAUD ALERT: Claim ${data.claim_id} referred to SIU (score: ${data.fraud_score.toFixed(2)})`,
    next_system: 'siu_case_management',
    payout_hold: true,
    processed_at: new Date().toISOString()
  }
}];
